<template lang="en">
    <transition name="modal">
            <div class="modal d-block my-popups dialog">
            <div class="modal-dialog">
            <div class="modal-content">
            <div class="modal-header">
            <slot name="header">  </slot>
            <button type="button" title="" v-on:click="$emit('close')" class="close" data-original-title="Close"><i class="fa fa-times" aria-hidden="true"></i></button>
            </div>
            <div class="modal-body">
            <span class="user-guide">
            <a class="ancuserguide" data-toggle="collapse" href="#collapseReply" role="button" aria-expanded="false" aria-controls="collapseExample">{{$t('UserGuide')}}</a>
            <div id="collapseReply" class="divancuserguide collapse">
            <div id="scrollbarreplyuserguide" class="custom-scrollbar-js">
            <div class="con" v-html="userGuide">{{userGuide}}</div>
            </div>
            </div>
            </span>
            <ValidationObserver ref="form" v-slot="{ handleSubmit }">
            <form  data-vv-scope="Note" v-on:submit.prevent="submitForm()">
                <div class="d-flex flex-wrap">
                <div class="col-md-12 p-0">
                <div class="row">
    
                <div class="col-sm-12 col-md-6 col-lg-6 col-xl-6 float-left">
                    <div class="form-group">
                        <ValidationProvider :rules="'required'" v-slot="{errors}">
                            <label>Visibility<span class="text-danger">*</span></label>                     
                            <select v-bind:class="{'form-control': true}" name="Visibility" v-model="Visibility">
                                <option value="">Select</option>
                                <option value="true">{{$t('Public')}}</option>
                                <option value="false">{{$t('Private')}}</option>
                            </select>
                            <span class="invalid-feedback d-block" v-if="errors[0]">{{ errors[0] }}</span>
                        </ValidationProvider>
                    </div>
                </div>
                <div class="col-sm-12 col-md-12 col-lg-6 col-xl-6 float-left">
                <div class="form-group">
                <label>{{$t('Task')}} :</label></span>
        
                <select id="TaskDropdown" name="TaskDropdown" v-model="Task" v-bind:class="{'form-control bg-light': typeNoteTask == '','form-control bg-light disabled': typeNoteTask != ''}">
                <option value="">{{$t('Select')}}</option>
                <option v-for="tsk in TaskData" v-bind:value="tsk.TASK_ID">
                {{ tsk.TASK_NAME }}
                </option>
                </select>
            
                <div  class="invalid-feedback"></div>
                
                </div>
                </div>
    
    
                <div class="col-sm-12 col-md-12 col-lg-12 col-xl-12 float-left">
                    <div class="form-group">
                        <ValidationProvider name="Description" :rules="submitted ? 'required' : ''" v-slot="{errors}">
                            <label>{{$t('Description')}}<span class="text-danger">*</span></label>                       
                            <ckeditor :editor="editor" class="mb-0" v-bind:class="{'form-group': true}" name="Description" id="Description" maxlength="8000" v-model="Description" cols="20"></ckeditor>
                            <span class="invalid-feedback d-block" v-if="errors[0]">{{ errors[0] }}</span>
                        </ValidationProvider> 
                    </div>
                </div>
                </div>
                <div class="row flex-row-reverse">
                <div class="col-lg-6 text-right">
                <button href="javascript:;" class="btn btn-success formbtn text-white mr-2 saveNote" type="submit"><i class="fa fa-save pr-2"></i>{{$t('Save')}}</button>
                <a v-on:click="$emit('close')" class="btn btn-danger formbtn widthhalf text-white"><i class="fa fa-close pr-2"></i>{{$t('Cancel')}}</a>
                </div>
                <div class="col-lg-6">
                <div class="py-2 mandatory">{{$t('MandatoryString')}}
                </div>
                </div>
                </div>
                </div>
                </div>
            </form>
            </ValidationObserver>
            </div>
            </div>
            </div>
            </div>
            </transition>
    </template>
<script>
import DataService from '../../services/DataService';
import {
    ValidationProvider,
    extend,
    ValidationObserver
} from 'vee-validate';

extend('required', {
    validate(value) {
        return {
            required: true,
            valid: ['', null, undefined].indexOf(value) === -1
        };
    },  
    computesRequired: true
});
export default {
    name: 'modalAddNote',
    components: {      
        ValidationProvider,
        ValidationObserver,
    },
    props: {
        taskid: {
            type: String
        },
    },
    data: function () {
        return {
            noteId: null,
            Visibility: '',
            Task: '',
            Description: '',
            modal: null,
            isView: false,
            isPublic: false,
            userGuide: '',
            TaskData: [],
            typeNoteTask: '',
            submitted: false,
            editor: this.CLASSIC_EDITOR
        }
    },
    created: function () {
        if (this.$parent.modalNoteItem != null && typeof this.$parent.modalNoteItem != 'undefined') {
            this.modal = this.$parent.modalNoteItem;
            this.noteId = this.$parent.modalNoteItem.NOTE_ID;
            this.Visibility = this.$parent.modalNoteItem.IS_PUBLIC;
            this.Task = this.$parent.modalNoteItem.TASK_ID;
            this.Description = this.$parent.modalNoteItem.NOTE_CONTENT;
            this.ProjectId = this.$parent.modalNoteItem.PROJECT_ID;

        }
        if (this.taskid != null) {
            this.Task = this.taskid;
            this.typeNoteTask = this.$parent.typeNoteTask;
        }
        this.userGuide = this.$parent.AddNoteUserGuide;
        this.TaskDropdown();
    },
    methods: {
        submitForm: function () {
            console.log("clicked");
            var vm = this;
            vm.submitted = true;
            this.$refs.form.validate().then(success => {
                if (success) {
                    var data = {
                        noteId: vm.noteId == null ? 0 : vm.noteId,
                        description: vm.Description == null ? 0 : vm.Description,
                        isPublic: vm.Visibility == null ? false : vm.Visibility,
                        projectId: vm.$parent.ProjectId == null ? 0 : vm.$parent.ProjectId,
                        taskId: vm.Task == null ? null : vm.Task,
                        moduleName: vm.$parent.ModuleName,
                    };
                    var objectPostString = JSON.stringify(data);
                    DataService.SaveNote(objectPostString).then(function (response) {
                        console.log(response)
                        if (response.data.status == "Success") {
                            // debugger;
                            vm.ShowAlert(vm.$t("RecordsSavedSuccessfully"), 'success', true, vm.$t('Alert'));
                            vm.showAddNoteModal = false;
                            vm.$emit('close');

                            vm.$parent.FetchData('kanban', null);

                        }
                        vm.isLoading = false;
                    }, function (response) {
                        vm.isLoading = false;
                    });
                }
            });
        },
        TaskDropdown: function () {
            var vm = this;
            vm.isLoading = true;
            var params = "projectId=" + vm.$parent.ProjectId;
            DataService.LoadTaskByProjectId(params).then(function (response) {
                vm.isLoading = false;
                if (response.data != null && response.data != "") {
                    vm.TaskData = response.data.result.DATA;
                }
            });
        }
    }
}
</script>