        async submitProjectInfo(info, ths) {
            var vm = ths
            // let param = 'projectId='+info?.projectId+'&trackDescription='+info?.trackDescription+'&taskId='+info?.taskId+'&isBillable=0&startTime='+info.startTime+'&stopTime='+info.stopTime+'&currentDate='+info.currentDate+'&timeformat='+info.timeformat+'&type='+info.type;
            this.loading = true
            try {

                const { data } = await DataService.SaveProjectInfo(info);
                this.getMessageAlert = data
                this.timerRunResponse = data
                if (data.userMsg) {
                    let message = data.userMsg
                    if (data.userMsg == "stop") {
                        vm.ShowAlert(vm.$t('TimeEntryStopSuccessfully'), "success", true, vm.$t('Alert'));
                    }
                    else if (data.userMsg == "TimerResumedAlready") {
                        vm.ShowAlert(vm.$t('TimerResumedAlready'), "danger", true, vm.$t('Alert'));
                    }
                    // else if(data.userMsg=="TimerStopped"){
                    //     ShowAlert(vm.$t('TimerStopped'), "danger", true, vm.$t('Alert'));

                    // }
                    else if (data.userMsg == "TimerStartedAlready") {
                        vm.ShowAlert(vm.$t('TimerStartedAlready'), "danger", true, vm.$t('Alert'));
                    }
                    else if (data.userMsg == "TimerPaused" || data.userMsg == "TimerPausedAlready") {
                        vm.ShowAlert(vm.$t('TimerPausedAlready'), "danger", true, vm.$t('Alert'));
                    }
                    else if (data.userMsg == "AllowTrackingTimeOnHoliday_desc") {
                        vm.ShowAlert(vm.$t('AllowTrackingTimeOnHoliday_desc'), "warning", true, vm.$t('Alert'));
                    }
                    else if (data.userMsg == "EtreesApprovedpending") {
                        vm.ShowAlert(vm.$t('EtreesApprovedpending'), "warning", true, vm.$t('Alert'));
                    }
                    else if (data.userMsg == "OverTimeNotAllowed") {
                        vm.ShowAlert(vm.$t('OverTimeNotAllowed'), "warning", true, vm.$t('Alert'));
                    }
                    else if (data.userMsg == "ProjectNotAssign") {
                        vm.ShowAlert(vm.$t('ProjectNotAssign'), "warning", true, vm.$t('Alert'));

                    }
                    else if (data.userMsg == "BreakEntryRunning") {
                        vm.ShowAlert(vm.$t('BreakEntryRunning'), "warning", true, vm.$t('Alert'));

                    }
                    else if (data.userMsg == "TaskNotAssign" && data.status == 103) {
                        vm.ShowAlert(vm.$t('TaskNotAssign'), "warning", true, vm.$t('Alert'));

                    }
                    else if (data.userMsg = "Breakstop") {
                        vm.ShowAlert(ths.$t('BreakEntryStopSuccessfully'), "success", true, ths.$t('Alert'));
                    }
                    else {
                        vm.ShowAlert(message, "danger", true, vm.$t('Alert'));
                    }

                }
                if (data.status == 'overlap') {
                    vm.ShowAlert(vm.$t('OverlapCheck'), "warning", true, vm.$t('Alert'));
                }
            } catch (e) {
                console.log(e)
            }
            this.loading = false
        },
