        buildHierarchy(items) {

            const map = {};
            const root = [];

            // Create a mapping of items by their value
            items.forEach(item => {
                map[item.value] = item;
            });
            console.log('items', items);
            // Iterate over items to build the hierarchy
            items.forEach(item => {
                item.id = item.value;
                item.label = item.text;
                const parentValue = item.parentValue;
                // If the item has a parent, add it to the parent's children array
                if (parentValue != 0) {
                    const parent = map[parentValue];
                    if (parent) {
                        console.log('parent', parent);
                        parent.children = parent.children || [];
                        parent.children.push(item);
                    }
                } else {
                    // If the item has no parent, add it to the root array
                    root.push(item);
                }
            });
            return root;
        },


