<template>
    <section>
        
    <div class="modal my-popups right fade show d-block">
        <div class="modal-dialog maxwidth500" role="document">
            <div class="modal-content">
                <div class="modal-header">
                    <button type="button" class="close" v-on:click="CloseQuickView()" data-dismiss="modal"><i
                            class="fa fa-times" aria-hidden="true"></i></button>
                    <h4 class="modal-title text-truncate pb-1" id="myModalLabel">{{ TASK_NAME }} {{ QuickViewType }}</h4>
                </div>
                
                <div class="modal-body">
                    <div class="white_bx"> 
                        <div class="col-lg-12 p-0" >
                            <div id="status" class="heading-border mb-3" v-if="QuickViewType != 'attachment'">
                                <h5 class="h5"><span>{{ $t('Progress') }}</span>

                                    <div class="btnnot px-2 text-white d-block text-center" 
                                     style="background-color: rgb(40, 167, 69); color: rgb(255, 255, 255);">{{ ProjectStatus }}</div>
                                </h5>
                            </div>
                            <div class="level_info mb-3" v-if="QuickViewType != 'attachment'">
                                <ul > 
                                    <li><b style="color: rgb(35, 165, 253);">{{ ConvertTimeToHours(AllocateHours) }}</b> {{$t('AllocatedHours')}}</li>
                                    <li><b style="color: rgb(40, 167, 69);">{{ ConvertTimeToHours(TrackHours) }}</b> {{$t('TrackedHour')}} </li>
                                </ul>
                                <div class="progress prog_bx"> 
                                    <div role="progressbar" aria-valuenow="0" aria-valuemin="0" aria-valuemax="100"
                                        class="progress-bar" :class="{'bg-sky':ExtraHours > 0,'bg-red':ExtraHours < 0}" :style="'width:'+  HoursDonePercentage + '%'"></div>
                                </div>
                                <ul v-if="ExtraHours < 0">
                                    <li><b style="color:#ff0000">{{ExceedHours}}</b> {{$t('exceedhours')}}</li>
                                </ul> 
                            </div>
                            <div class="col-lg-12 p-0">
                                <div id="status" class="heading-border mb-3" v-if="QuickViewType != 'attachment'">
                                        <h5 class="h5"><span>{{$t('Details')}}</span></h5>
                                </div>
                                <ul class="detail_list" v-if="QuickViewType != 'attachment'">
                                    <li><b>{{$t('ProjectName')}}</b><span :title="PROJECT_NAME || '--'">  {{ TruncateStr(PROJECT_NAME, 15) }}</span></li>
                                    <li><b>{{$t('ProjectManager')}}:</b><span :title="PM || '--'">{{ TruncateStr(PM, 15) }}</span></li>
                                    <li><b>{{$t('Isbillable')}}:</b> <span> {{ IS_BILLABLE == false ? 'No' : 'Yes' }}</span></li>
                                    <li><b>{{$t('parenttaskname')}}:</b> <span> {{ PARENT_TASK || '--'}} </span></li>
                                    <li><b>{{$t('TaskName')}}:</b> <span> {{ TASK_NAME }}</span></li>
                                    <li><b>{{$t('ReportStartDate')}}:</b>   <span>{{ START_DATE ? $d(START_DATE) : '--' }}</span></li>
                                    <li><b>{{$t('ReportEndDate')}}:</b>   <span>{{ END_DATE ? $d(END_DATE) : '--' }}</span></li>
                                    <li><b>{{$t('TaskDescription')}}:</b><span v-html="TASK_DESCRIPTION ? (TASK_DESCRIPTION | TruncateStr(TASK_DESCRIPTION,15)): '--'"></span></li>
                                    <li><b>{{$t('TaskRate')}}:</b> <span> {{ TASK_RATE }}</span></li>
                                </ul>
                                <div id="status" class="heading-border mb-3" v-if="QuickViewType != 'attachment'" >
                                    <h5 class="h5"><span>{{$t('Team')}}</span></h5>
                                </div>
                                <div id="divscrollsetuptabs" class="p-0 col-12"
                                    style="max-height: 300px; overflow: auto;" v-if="QuickViewType != 'attachment'">  
                                    <div id="mCSB_15" class="mCustomScrollBox mCS-dark-thick mCSB_vertical mCSB_inside" tabindex="0" style="max-height: none;">
                                        <div id="mCSB_15_container" class="mCSB_container" style="position: relative; top: 0px; left: 0px;" dir="ltr">
                                    <div class="customer-headersmall float-left w-100 mb-3" v-for="(projectteam, indexpProjectTeam) in GetQuickViewListingData.project_team" :key="indexpProjectTeam">
                                      {{projectteam.Image_Url }}
                                      <div class="name-circle" style="background: rgb(195 207 213 / 84%);">
                                            <span class="initials user-img-con">                                              
                                                {{ getFirstTwoInitials(projectteam.Team_Name) }}
                                            </span>
                                        </div>
                                        <div class="conversation-header">
                                            <span>
                                                <span class="sender-name">{{ projectteam.Team_Name }}</span>                                                    
                                            </span>                                            
                                        </div>
                                    </div>
                                    </div>
                                    <div id="mCSB_15_scrollbar_vertical" class="mCSB_scrollTools mCSB_15_scrollbar mCS-dark-thick mCSB_scrollTools_vertical" style="display: block;"><div class="mCSB_draggerContainer"><div id="mCSB_15_dragger_vertical" class="mCSB_dragger" style="position: absolute; min-height: 30px; display: block; height: 197px; max-height: 290px; top: 0px;"><div class="mCSB_dragger_bar" style="line-height: 30px;"></div></div><div class="mCSB_draggerRail"></div></div></div>
                                    <div class="text-center text-danger d-flex align-items-center justify-content-center borderbababa p-2 mb-4 no-record" v-if="ProjectTeam == ''">
                                        {{ $t('NoRecordfound') }}
                                    </div>
                                </div>
                                </div>
                                <div v-if="ModuleNameAll != 'HR'" class="heading-border mb-3 pt-2" id="status">
                                    <h5 class="h5"><span>Files</span></h5>
                                    <div class="text_link">
                                        <a href="javascript:;" v-if="ShowDiv" v-on:click="openUploadFileModel(projectId)"><i
                                                class="fa fa-paperclip pr-2"></i>{{$t('Add_Files')}}</a>
                                        <a href="javascript:;" v-if="!ShowDiv" v-on:click="BackDetail()"><i
                                                class="fa fa-angle-double-left pr-2"></i>{{ $t('Back') }}</a>
                                    </div>
                                </div>
                                <div v-if="ModuleNameAll != 'HR'" class="w-100" id="divscrollsetupfile"
                                    style="max-height: 200px; overflow-y:auto;">
                                    <div v-if="!noRecordForDetail">
                                    <a class="p-1 m-1 d-block" v-on:click="DownloadFile(item)" v-bind:title="item.LATEST_FILE_NAME" href="javascript:;" v-for="(item, index) in fileData"  :key="index">
                                        <span>{{  item.LATEST_FILE_NAME}} {{ Item.LATEST_VERSION }}</span>
                                    </a>
                                    </div>
                                    <div v-if="noRecordForDetail"
                                        class="text-center text-danger d-flex align-items-center justify-content-center borderbababa p-2 mb-4 no-record">
                                        {{ $t('NoRecordfound') }}</div>
                                </div>
                                <ul class="file-list" v-if="ShowDiv">
                                    <li v-if="ModuleNameAll != 'HR'" v-on:click="GetDetail('IMAGES', projectId)"
                                        style="cursor:pointer">
                                        <span class="fldr-icon"><i class="fa fa-folder"></i></span>
                                        <span class="m-text">{{$t("Image")}}</span>
                                        <small>{{ Images }} {{$t('Items')}}</small>
                                        <a href="javascript:;" class="right-acti d-none"><i
                                                class="fa fa-ellipsis-h"></i></a>
                                    </li>
                                    <li v-if="ModuleNameAll != 'HR'" v-on:click="GetDetail('DOCUMENTS', projectId)"
                                        style="cursor:pointer">
                                        <span class="fldr-icon"><i class="fa fa-folder"></i></span>
                                         <span class="m-text">{{$t("Documents") }}</span>  
                                        <small>{{ Documents }} {{$t('Items')}}</small>
                                        <a href="javascript:;" class="right-acti d-none"><i
                                                class="fa fa-ellipsis-h"></i></a>
                                    </li>
                                    <li v-if="ModuleNameAll != 'HR'" v-on:click="GetDetail('VIDEOS', projectId)"
                                        style="cursor:pointer">
                                        <span class="fldr-icon"><i class="fa fa-folder"></i></span>
                                          <span class="m-text">{{ $t("Videos") }}</span>
                                        <small>{{ Videos }} {{$t('Items')}}</small>
                                        <a href="javascript:;" class="right-acti d-none"><i
                                                class="fa fa-ellipsis-h"></i></a>
                                    </li>
                                </ul>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    </div>
    <Addfiles v-if="ShowManageFile" v-on:close="ShowManageFile = false" :ProjectDetails="ProjectDetails" :taskId="taskId" v-on:closeUpdateModal="QuickViewByProjectId(ProjectDetails,taskId)" v-on:fetchData="fetchData()" />
</section>
</template>
<script>
import DataService from '../../services/DataService';
import Addfiles from '@/components/Modal/AddFile.vue'
import { convertSecondToHHMM } from "@/assets/common/vue-common.js"
export default {
    components: {
         Addfiles
    },
    props: {
      
    },
    created() {
        this.QuickViewType = this.$parent.QuickViewType;
        if (this.$parent.modalProjectId != null) {
        this.projectId = this.$parent.modalProjectId;
        this.taskId = this.$parent.modalTaskId;
        this.QuickViewByProjectId(this.$parent.modalProjectId, this.$parent.modalTaskId);
        }
    },

    data() {
        return {
            PROJECT_NAME: '',
                ProjectStatus: '',
                ACTIVE_TASK: '',
                IS_BILLABLE: '',
                PARENT_TASK: '',
                TASK_DESCRIPTION: '',
                TASK_NAME: '',
                TASK_RATE: '',
                START_DATE: '',
                END_DATE: '',
                PM: '',
                Images: 0,
                Videos: 0,
                Documents: 0,
                ProjectTeam: [],
                STATUS_COLOR: '',
                STATUS_BG_COLOR: '',
                secondsPerMinute: 60,
                minutesPerHour: 60,
                AllocateHours: 0,
                AllocateHoursSecond: 0,
                TrackHours: 0,
                TrackHoursSecond: 0,
                HoursDonePercentage: 0,
                HoursToDoPercentage: 0,
                ProjectHours: 0,
                ExtraHours: 0,
                ExceedHours: 0,
                projectId: 0,
                taskId: 0,
                PageSize: 10,
                PageNumber: 1,
                ModelSortBy: '',
                ModelSortExp: '',
                noRecordForDetail: false,
                fileData: [],
                ShowDiv: true,
                QuickViewType: '',
                ModuleNameAll: '',
                ShowManageFile:false,
                GetQuickViewListingData:[],
                ProjectDetails:0
        }

    },
    methods: {
        QuickViewByProjectId: function (project_id, task_id) {
            var vm = this;
            debugger
            var params = `projectId=${vm.projectId}&taskId=${vm.taskId}`;
            DataService.GetQuickViewByProjectIdTaskId(params).then(response => {
                debugger
                console.log("this",response);
                if (response.data.code != '0') {
                    vm.GetQuickViewListingData = response.data.result;
                    vm.PROJECT_NAME = response.data.result.project_detail[0].PROJECT_NAME;
                    vm.ProjectStatus = response.data.result.project_detail[0].ProjectStatus;
                    vm.ACTIVE_TASK = response.data.result.project_detail[0].ACTIVE_TASK;
                    vm.IS_BILLABLE = response.data.result.project_detail[0].IS_BILLABLE;
                    vm.PARENT_TASK = response.data.result.project_detail[0].PARENT_TASK;
                    vm.TASK_NAME = response.data.result.project_detail[0].TASK_NAME;
                    vm.TASK_RATE = response.data.result.project_detail[0].RATE;
                    vm.TASK_DESCRIPTION = response.data.result.project_detail[0].TASK_DESCRIPTION;
                    vm.START_DATE = response.data.result.project_detail[0].START_DATE == null ? '--' : new Date(response.data.result.project_detail[0].START_DATE);
                    vm.END_DATE = response.data.result.project_detail[0].END_DATE == null ? '--' : new Date(response.data.result.project_detail[0].END_DATE);
                    vm.STATUS_COLOR = response.data.result.project_detail[0].STATUS_COLOR;
                    vm.STATUS_BG_COLOR = response.data.result.project_detail[0].STATUS_BG_COLOR;
                    vm.PM = response.data.result.project_detail[0].PM == null ? '--' : response.data.result.project_detail[0].PM;                    
                    vm.Images = response.data.result.project_files[0].Images;
                    vm.Videos = response.data.result.project_files[0].Videos;
                    vm.Documents = response.data.result.project_files[0].Documents;                    
                    vm.ProjectTeam = response.data.result.project_team;                    
                    vm.AllocateHours = response.data.result.project_hours.length == 0 ? 0 : convertSecondToHHMM(response.data.result.project_hours[0].TOTAL_TASK_HOURS);
                    vm.TrackHours = response.data.result.project_hours.length == 0 ? 0 : convertSecondToHHMM(response.data.result.project_hours[0].TRACK_SECONDS);
                    vm.AllocateHoursSecond = response.data.result.project_hours.length == 0 ? 0 : response.data.result.project_hours[0].TOTAL_TASK_HOURS;
                    vm.TrackHoursSecond = response.data.result.project_hours.length == 0 ? 0 : response.data.result.project_hours[0].TRACK_SECONDS;
                    vm.ExtraHours = response.data.result.project_hours.length == 0 ? 0 : vm.GetExtraHours(response.data.result.project_hours[0].REMAINING_SECONDS);
                    vm.ExceedHours =convertSecondToHHMM(Math.abs(vm.ExtraHours)) 
                    vm.HoursDonePercentage = response.data.result.project_hours.length == 0 ? 0 : vm.GetPercentage(response.data.result.project_hours[0].COMPLETED);
                }
            });
        },
        fetchData:function(){
            this.$emit('closeUpdateModal')
        },
          getInitials(name) {
      if (!name) return 'U';
      return name
        .split(' ')
        .map(n => n[0])
        .join('')
        .toUpperCase()
        .substring(0, 2);
    },
        GetDetail: function (type, projectId) {
            debugger
            var vm = this;
            vm.ShowDiv = false;
            vm.fileData = [];
            var params =  `projectId=${projectId}&pageSize=${vm.$parent.PageSize}&pageNum=${vm.$parent.PageNumber}&sortBy=${vm.ModelSortBy}&sortExp=${vm.ModelSortExp}&viewType=${type}`;              
            DataService.GetFileDetails(params).then(response => {
                debugger
                if (response.data != null && response.data.status == "Success") {
                    if (response.data.result.data.length > 0) {
                        vm.fileData = response.data.result.data;
                        vm.noRecordForDetail = false;                    }
                    else {
                        vm.noRecordForDetail = true;
                    }
                } else {
                    vm.noRecordForDetail = true;

                }
            });
        },
        CloseQuickView: function () {
            var vm = this;
            vm.$parent.ShowManageProjectQuickView = false;
        },
        BackDetail: function () {
                var vm = this;
                vm.ShowDiv = true;
                vm.fileData = [];
                vm.noRecordForDetail = false;
            },           
            async DownloadFile(item) {
                var vm = this;
                console.log("item",item)
                var param = `fileId=${item.FILE_VERSION_ID}&IsVersion=1`
                await DataService.DownloadSingleFile(param).then(function (response) {                 
                    var fileLink = document.createElement('a');
                    var fileURL = window.URL.createObjectURL(new Blob([response.data],{ type: response.data.type}));
                    fileLink.href = fileURL;
                    fileLink.setAttribute('download', item.LATEST_FILE_NAME);
                    document.body.appendChild(fileLink);
                    fileLink.click();
                });          
        },
            openUploadFileModel: function (data) {
                this.ProjectDetails = data;              
                this.ShowManageFile=true;
            },
            GetExtraHours: function () {
                var vm = this;
                var ehours = vm.AllocateHoursSecond - vm.TrackHoursSecond
                return ehours;
            },
            GetPercentage: function () {
                var vm = this;
                var val = 100;
                var percentage = vm.ExtraHours / vm.AllocateHoursSecond * 100;
                return (val-percentage);
            },
            ConvertTimeToHours(Hours){
                if(Hours!=0){
                var getHour = Hours.split(":");
                var obj = getHour[0] + ' h ' + getHour[1] + ' m'
                return obj;
                }
                else{
                    return '00 h 00 m'
                }
               
            },
            getFirstTwoInitials(fullName) {
                if (!fullName) return "";
                const parts = fullName.trim().split(/\s+/);
                return (parts[0][0] + (parts[1]?.[0] || "")).toUpperCase();
            }
            
    }

}

</script>