<script>
import DataService from '../../services/DataService';
import moment from 'moment';
import {
    formatter,
    convertSecondToHHMM,
    getSecondsFromDate
} from "@/assets/common/vue-common.js";
import AddManualModal from "../../components/Modal/AddManualModal.vue";
import Comments from "../../components/Modal/Comments.vue";
import RequestTimeModal from "../../components/Modal/RequestTimeModal.vue";

import Files from '@/components/Modal/todoListFiles.vue';
import AddNote from "@/components/Modal/modalAddNote.vue";
import UpdateProgress from '@/components/Modal/updateProgress.vue';
import modaltracklocation from "@/components/Modal/modaltracklocation.vue";

import NoteListPopUp from "@/components/Modal/modalNoteListPopUp.vue";
import {
    userTimerInfo
} from "@/stores/TimeTrack.js";
import { required } from 'vee-validate/dist/rules';
export default {
    name: "ToDo List Canban View",
    components: {
        AddManualModal,
        Comments,
        RequestTimeModal,
        Files,
        NoteListPopUp,
        AddNote,
        UpdateProgress,
        modaltracklocation,

    },
    props: {
        status: {
            type: String,
            required: false
        },
        module: {
            type: String,
            required: true,
        }
    },
    setup() {
        const store = userTimerInfo();
        return {
            store
        }
    },
    data() {
        return {
            ShowManageProjectQuickView: false,
            showTrackLocationModal: false,
            showUpdateProgressModal: false,
            toDoList: [],
            Timer: '',
            globalTime: '',
            secondsPerMinute: 60,
            minutesPerHour: 60,
            Date: '',
            noRecordToDoList: false,
            PageNumber: 1,
            PageSize: 10,
            SortBy: '',
            SortExp: '',
            PageSizeOption: null,
            CurrentPage: 1,
            TotalPages: 0,
            projectName: '',
            Status: '',
            //EndDateForSearch: '',
            TotalRecords: 0,
            TRACKED_HOURS: '',
            PROJECT_ID: '',
            TASK_ID: '',
            PROGRESS: '',
            PendingRecords: 0,
            ProgressRecords: 0,
            OverdueRecords: 0,
            UpcomingRecords: 0,
            CompletedRecords: 0,
            cardViewData: [],
            TagData: [],
            TrackId: 0,
            pendingData: [],
            inprogressData: [],
            comData: [],
            MaxCount: 0,
            showNoteModal: false,
            modalNoteTaskItem: null,
            showAddNoteModal: false,
            modalNoteItem: null,
            header: '',
            TaskId1: null,
            ProjectId: null,
            ModuleName: 'TODOLIST',
            ModuleNameAll: '',
            isLoading: false,
            isActiveWeeklyStatus: true,
            trackerData: {
                projectId: 0,
                trackDescription: "",
                taskId: 0,
                isBillable: 0,
                format: false,
                date: null,
                trackId: 0,
                startTime: moment().format("YYYY-MM-DD HH:mm:ss"),
                stopTime: moment().format("YYYY-MM-DD HH:mm:ss"),
                companyId: null,
                currentDate: moment().format("YYYY-MM-DD HH:mm:ss"),
                trackAgent: "web",
                timerStatus: "start",
                CreatedBy: this.store.getUserInformation.id,
                createdBy: this.store.getUserInformation.id,
                linkedTrackId: null,
                totalHours: 0,
                timeformat: 12,
                TagIds: "",
                isForcedUpdate: null,
                type: "TimeTrack",
                trackType: "TimeTrack",
                BreakDate: null,
                BreakName: null,
                BreakId: '',
                BreakStartTime: 0,
                Shift_ID: 0,
                SelectedDate: "",
                Break_Shift: "",
            },
            series: [],
            series1: [],
            chartOptions: {

            },
            chartOptions1: {

            },
            seriesbar: [],
            chartOptionsBar: {},

            addManualShow: false,
            commentsShow: false,
            requestShow: false,
            fromData: {},
            buttonIndex: '',
            isActiveActionButton: false,
            DataArray: [],
            DraggedFromElementStatus: "",
            DraggedToElementStatus: "",
            DraggedElementTaskId: null,
            DraggedElementStatus: null,
        }
    },
    created() {
        // this.status='PENDING,INPROGRESS'
        // this.Status='PENDING,INPROGRESS'
        this.StatusDropdown();
        this.Status = this.status;
        this.FetchData();
        Object.assign(this.fromData, this.trackerData)
        this.store.getTimerInfo();
    },
    mounted() {
        const canbanScroll = document.querySelector('.onlyd-view');
        let previousScrollTop = canbanScroll.scrollTop;

        canbanScroll.addEventListener('scroll', e => {
            const currentScrollTop = canbanScroll.scrollTop;

            if (currentScrollTop + canbanScroll.clientHeight >= canbanScroll.scrollHeight) {
                // Scrolling down
                console.log("Scrolling Down");
                if (this.TotalPages > this.PageNumber) {
                    this.PageNumber = this.PageNumber + 1;
                    this.FetchData('scroll');
                }
                canbanScroll.scrollTop = 1810;
            } else if (currentScrollTop == 0) {
                // Scrolling up
                console.log("Scrolling Up");
                if (this.PageNumber > 1) {
                    this.PageNumber = this.PageNumber - 1;
                    this.FetchData('scroll');
                }
            }

            // Update previous scroll position
            previousScrollTop = currentScrollTop;
        });
    },


    methods: {
        StatusDropdown: function () {
            debugger;
            var vm = this;
            //showLoader();

            var url = "langCode=en&statusType=Project&hasGlobal=1";
            DataService.StatusDropdown(url).then(function (response) {
                //hideLoader();
                if (response.data != null && response.data != "") {
                    //vm.StatusData = response.data.result.data;
                    vm.StatusList = response.data.result.data;

                    vm.pendingData = $.grep(vm.StatusList, function (element, index) {
                        return element.STATUS_CODE == 'REFPEN';
                    });
                    vm.inprogressData = $.grep(vm.StatusList, function (element, index) {
                        return element.STATUS_CODE == 'PNPGRS';
                    });
                    vm.comData = $.grep(vm.StatusList, function (element, index) {
                        return element.STATUS_CODE == 'STATUS_DONE';
                    });
                }
            });
        },
        ShowDataArray: function () {
            var vm = this;
            var array = [];
            array.push({
                name: "overdue",
                count: 0,
                data: [],
                show: 1,
                className: "canceled",
                SortIcon: "fa-sort-alpha-desc",
                StatusId: 0
            });
            array.push({
                name: "pending",
                count: 0,
                data: [],
                show: 1,
                className: "pending",
                SortIcon: "fa-sort-alpha-desc",
                StatusId: vm.pendingData[0].STATUS_ID
            });
            array.push({
                name: "inprogress",
                count: 0,
                data: [],
                show: 1,
                className: "overdue",
                SortIcon: "fa-sort-alpha-desc",
                StatusId: vm.inprogressData[0].STATUS_ID
            });
            array.push({
                name: "completed",
                count: 0,
                data: [],
                show: 1,
                className: "upcoming",
                SortIcon: "fa-sort-alpha-desc",
                StatusId: vm.comData[0].STATUS_ID
            });
            array.push({
                name: "upcoming",
                count: 0,
                data: [],
                show: 1,
                className: "inactive",
                SortIcon: "fa-sort-alpha-desc",
                StatusId: 0
            });
            this.DataArray = array;
        },

        async FetchData(e) {
            debugger;
            var vueObj = this;
            vueObj.isLoading = true;

            // Reset data if not scrolling
            if (e !== 'scroll') {
                vueObj.DataArray.forEach(item => item.data = []);
                vueObj.toDoList = [];
                vueObj.TagData = [];
            }

            // Build the URL for the API request
            let url = `pageSize=${this.PageSize}&pageNumber=${this.PageNumber}&sortBy=${this.SortBy}&sortExp=${this.SortExp}&projectId=&type=kanban`;

            if (this.module) {
                url += `&moduleNameForSearch=${this.module}`;
            } else {
                url += `&moduleNameForSearch=''`;
            }

            if (this.Status) {
                url += `&status=${this.Status}`;
            } else {
                url += `&status=`;
            }

            console.log("url", url);

            try {
                // Fetch data from the API
                const response = await DataService.GetToDoListing(url);
                var responseData = response.data.result.DATA;

                vueObj.ShowDataArray();

                if (responseData && responseData.length) {
                    vueObj.toDoList = responseData;
                    console.log("vueObj.toDoList", vueObj.toDoList)
                    // Update DataArray based on responseData
                    vueObj.DataArray.forEach(item => {
                        const name = item.name;
                        switch (item.name) {
                            case 'overdue':
                                item.count = vueObj.toDoList[0].OVERDUERECORDS || 0;
                                break;
                            case 'pending':
                                item.count = vueObj.toDoList[0].PENDINGRECORDS || 0;
                                break;
                            case 'inprogress':
                                item.count = vueObj.toDoList[0].PROGRESSRECORDS || 0;
                                break;
                            case 'upcoming':
                                item.count = vueObj.toDoList[0].UPCOMINGRECORDS || 0;
                                break;
                            case 'completed':
                                item.count = vueObj.toDoList[0].COMPLETEDRECORDS || 0;
                                break;
                            default:
                                item.count = 0;
                                break;
                        }
                        const data = responseData.filter(element => element.STATUS.toLowerCase() === name);
                        item.data = data;
                    });

                    // Calculate total pages and update other data
                    vueObj.TotalPages = Math.ceil(vueObj.toDoList[0].TOTALRECORDS / vueObj.PageSize);
                    vueObj.CurrentPage = vueObj.PageNumber;
                    vueObj.TagData = response.data.result.TAGDATA;
                }

            } catch (error) {
                console.error("Error fetching data:", error);
            } finally {
                vueObj.isLoading = false;
            }
