        showTrackPercent: function (item) {
            //debugger;
            var percent = 0;
            percent = (item.TRACKED_HOURS / ((item.ALLOCATE_HOURS) * 3600));
            percent = percent * 100;
            percent = parseFloat(percent, 10).toFixed(1);
            //if(percent==0)
            //{
            //    percent= item.ALLOCATE_HOURS * 3600;
            //}
            if (percent <= 0 || isNaN(percent) || percent.toLowerCase() == 'infinity') {
                percent = 100;
            } else {
                percent = 100 - percent;
            }
            if (Math.sign(percent) < 0) {
                percent = 0;
            }
            percent = Math.round(parseFloat(percent, 10));
            return percent;
        },
