                                                                    <div class="form-group">
                                                                        <label>{{ $t('SelectYourTask') }}:</label>
                                                                        <multiselect @input="isBillableSatus" :placeholder="$t('searchTask')" class="form-control tt_ddr col border-0 p-0" id="exampleFormControlSelect2" v-model="trackerData.taskId" :options="store.getTasksFromProject" label="firstAttribute" track-by="value" :show-labels="false">
                                                                            <template slot="option" slot-scope="props">
                                                                                <div class="option__desc"><span class="option__title">{{
                                                                                    props.option.firstAttribute }}</span>
