                                                                                    <label class="float-right"> {{ props.option.thirdAttribute }}% </label>
                                                                                </div>
                                                                            </template>
                                                                            <span slot="noResult">{{ $t('No_Record_Found') }}</span>
                                                                        </multiselect>
    
                                                                    </div>
                                                                </div>
                                                                <div class="col-sm-12 col-md-12 col-lg-12 col-xl-12 float-left fields_left arabicpulright">
                                                                    <div class="form-group">
                                                                        <ValidationProvider :rules="trackerData.projectId ? '' : 'required'" v-slot="{ errors }" class="tt_textarea_span position-relative">
                                                                            <textarea id="Taskdescription" name="Description" v-model="trackerData.trackDescription" style="border-color: #BDBCBD; resize:none" rows="10" cols="2000" class="timertxtarea form-control" :class="errors[0] ? 'is-invalid' : ''" v-on:keydown="textCounter" v-on:keyup="textCounter" v-on:mouseout="textCounter" :placeholder="$t('PleaseEnterDescription')" maxlength="2000"></textarea>
                                                                            <span class="text-danger font-12">{{ errors[0] }}</span>
                                                                        </ValidationProvider>
                                                                        <br />
                                                                        <small>
                                                                            <strong>
                                                                                <span class="alert-warning px-2 mr-2" id="txtCount">{{ textCountertlength }}</span>
                                                                            </strong>
                                                                            {{ $t('CharactersLeft') }}
                                                                        </small>
                                                                    </div>
                                                                </div>
                                                            </div>
                                                        </div>
                                                    </div>
                                                    <div class="col-sm-12 col-md-12 col-lg-5 col-xl-5 float-left">
    
                                                        <div class="row">
                                                            <div class="col-sm-12 col-md-12 col-lg-12 col-xl-12 float-left common_multiselect">
                                                                <div class="form-group mb-0">
                                                                    <label> {{ $t('SelectTagName') }}: </label>
                                                                    <multiselect :placeholder="$t('searchTags')" :multiple="true" :class="store.getTags.length > 0 ? 'tt_ddr_1 col' : ''" class="form-group  border-0 p-0" v-model="tagSelect" :options="store.getTags" label="tagName" track-by="tagId" :show-labels="false" id="exampleFormControlSelect1">
                                                                        <span slot="noResult">{{ $t('No_Record_Found') }}</span>
                                                                    </multiselect>
                                                                </div>
                                                            </div>
    
                                                            <div class="col-sm-12 col-md-12 col-lg-12 col-xl-12 float-left">
                                                                <div class="chkbillable custom-control custom-checkbox custom-control-inline mb-3">
                                                                    <input type="checkbox" data-change-id="no" id="chkTaskBillable" v-model="trackerData.isBillable" class="custom-control-input" style="display: none;"><label class="custom-control-label universal-custom-control-label pt-1" for="chkTaskBillable"></label>
                                                                    {{ $t('Billable') }}
                                                                </div>
                                                            </div>
    
                                                            <div class="col-sm-12 col-md-12 col-lg-12 col-xl-12 float-left time-tracked mb-2">
                                                                <input id="txtTotal" class="DivTimer timerclck fontbold digitalbg form-control m-0" style="font-size: 18px;" v-model="totalHours">
    
                                                                <span class="px-2">
                                                                    {{ $t('TimeTracked') }}
                                                                </span>
    
                                                            </div>
    
                                                            <div id="Edit12HourFormat">
    
                                                                <div class="col-sm-12 col-md-12 col-lg-12 col-xl-12 float-left time-tracked mb-2 newtimertracked">
                                                                    <div class="input-group">
                                                                        <vue-timepicker v-model="startTime" format="HH:mm" hide-clear-button @input="getTimeDiff">
                                                                            <template v-slot:icon>
                                                                                <i class="fa fa-clock-o text-dark font-14 mx-2"></i>
                                                                            </template>
                                                                        </vue-timepicker>
    
                                                                        <span class="px-2 timedate-label">{{ $t('EventStartTime') }}</span>
                                                                    </div>
    
                                                                </div>
    
                                                                <div class="col-sm-12 col-md-12 col-lg-12 col-xl-12 float-left time-tracked mb-2 newtimertracked">
                                                                    <div class="input-group">
                                                                        <vue-timepicker v-model="endTime" format="HH:mm" hide-clear-button @input="getTimeDiff">
                                                                            <template v-slot:icon>
                                                                                <i class="fa fa-clock-o text-dark font-14 mx-2"></i>
                                                                            </template>
                                                                        </vue-timepicker>
    
                                                                        <span class="px-2 timedate-label">{{ $t('StopTime') }}</span>
                                                                    </div>
                                                                </div>
                                                            </div>
    
                                                            <div class="col-sm-12 col-md-12 col-lg-12 col-xl-12 float-left time-tracked mb-2 newtimertracked">
                                                                <div class="input-group">
    
                                                                    <DatePicker v-model="trackerData.DateSet" :popover="false" :masks="dateMask">
                                                                        <template #default="{ togglePopover, inputValue, inputEvents }">
                                                                            <input placeholder="M/D/YYYY" class="form-control datepicker_HS" :value="inputValue" v-on="inputEvents" />
                                                                            <div class="input-group-append cursor-pointer" v-on:click="togglePopover">
                                                                                <span class="input-group-text">
                                                                                    <em class="fa fa-calendar"></em>
                                                                                </span>
                                                                            </div>
                                                                            <span class="px-2 timedate-label">{{ $t('ExpenseDate') }}</span>
                                                                        </template>
                                                                    </DatePicker>
    
                                                                </div>
                                                            </div>
                                                        </div>
                                                    </div>
                                                    <div class="col-12 mt-3 float-left">
                                                        <div class="row flex-row-reverse">
                                                            <div class="col-lg-12 text-right">
                                                                <button id="btnUpdate" class="btn btn-success formbtn mr-1" type="submit"><i class="fa fa-save pr-2"></i>{{ $t('Update') }}</button>
                                                                <button class="btn btn-danger formbtn" @click="deleteEntry"><i class="fa fa-trash pr-2"></i>{{ $t('Delete') }}</button>
                                                            </div>
                                                        </div>
                                                    </div>
                                                </div>
                                            </form>
                                        </ValidationObserver>
                                    </div>
                                </section>
                            </section>
                        </div>
                    </div>
                </div>
            </div>
        </div>
        <Alert :type="store.getAlertMessage.type" :message="store.getAlertMessage.message" v-bind:open="store.getAlertMessage.open" v-on:close="store.$state.getMessageAlert.open = false" />
    </div>
    </template>
    
    <script>
    import {
        defineComponent,
        reactive,
        ref,
        toRefs
    } from '@vue/composition-api'
    import {
        ValidationProvider,
        extend,
        ValidationObserver
    } from 'vee-validate';
    import moment from "moment"
    import VueTimepicker from 'vue2-timepicker'
    import DatePicker from 'v-calendar/src/components/DatePicker.vue'
    import Alert from '../../Common/Alert.vue';
    import DataService from '../../services/DataService'
    //import i18n from '@/localization/index'
    import {
        getSecondsFromDate,
        formatter,
        dateAndTimeZone,
        dateTimeFromat,
        dateFormat,
    } from "@/assets/common/vue-common.js"
    extend('required', {
        validate(value) {
            return {
                required: true,
                valid: ['', null, undefined].indexOf(value) === -1
            };
        },
        message: '{_field_} is required',
        // This rule reports the `required` state of the field.
        computesRequired: true
    });
    export default defineComponent({
        name: "Update Timer",
        components: {
            ValidationProvider,
            ValidationObserver,
            VueTimepicker,
            DatePicker,
            Alert
        },
        props: {
            store: {
                type: Object
            },
            trackUpdatRecord: {
                type: Object
            }
        },
        created() {
    
            this.fatchData();
            this.store.$state.tasks = []
        },
        mounted() {},
        methods: {
            async fatchData() {
    
                this.store.tagGetForTimer();
                Object.assign(this.formData, this.trackerData);
                await this.store.getProjects()
                await this.store.getTimerInfo()
                this.trackUpdatRecord.PROJECT_ID != 0 ? this.projectId() : this.trackerData.projectId = null
                if (this.trackUpdatRecord.TASK_ID != 0) {
                    await this.store.loadTasks(this.trackUpdatRecord.PROJECT_ID);
                    this.taskId()
                } else {
                    this.trackerData.taskId = null
                }
    
                if (this.trackUpdatRecord.TAG_ID) {
                    let array = this.trackUpdatRecord.TAG_ID.split(',')
                    array.map((item) => {
                        this.tagSelect.push(this.store.getTags.find((data) => data.tagId == item))
                    })
    
                }
    
                this.trackerData.trackDescription = this.trackUpdatRecord.TRACK_DESCRIPTION
                this.startTime = this.trackUpdatRecord.TRACK_START_TIME
                this.endTime = this.trackUpdatRecord.TRACK_END_TIME
                this.trackerData.DateSet = this.trackUpdatRecord.DateSet
            },
            async submitForm() {
                if (this.validHours()) {
                    this.tagSelect.map((items, index) => {
                        this.trackerData.TagIds += index != 0 ? ',' + items.tagId : items.tagId
                    })
                    this.trackerData.trackId = this.trackUpdatRecord.TRACK_ID
                    this.trackerData.projectId = this.trackerData.projectId ? this.trackerData.projectId.projectId : null
                    this.trackerData.taskId = this.trackerData.taskId ? this.trackerData.taskId.value : null
                    await this.store.updateTrackEntry(this.trackerData)
                    if (this.store.getUpdateTrackEntryRes.status == 'TimerEntryUpdated') {
                        this.$emit('closeUpdateModal')
                        this.$emit('close')
    
                    }
                }
    
            },
            async deleteEntry() {
                var vm = this;
                var params = `ids=${this.trackUpdatRecord.TRACK_ID}&ActionType=Delete`;
                DataService.setAction(params).then((response) => {
                    //var data=response
                    if (response.data == "DeletedSuccessfully") {
                        vm.ShowAlert(vm.$t('DeletedSuccessfully'), "success", true, vm.$t('Alert'));
                        this.$emit('closeUpdateModal')
                        this.$emit('close')
                    } else {
                        vm.ShowAlert(vm.$t('Failure'), "error", true, vm.$t('Alert'));
                    }
    
                });
            },
            taskByProject() {
                this.store.$state.tasks = []
                this.trackerData.taskId =''
                if (this.trackerData.projectId) {
                    this.store.loadTasks(this.trackerData.projectId.projectId)
                } else {
                    //getTasksFromProject = []
                }
               
            },
            isBillableSatus() {
                this.trackerData.isBillable = this.trackerData.taskId.isBillable
                // console.log("checkk",this.trackerData.taskId.isBillable)
            },
            // Description text length counter
            textCounter() {
                this.textCountertlength = 2000 - this.trackerData.trackDescription.length
            },
            //If project id get number from backend then set custom object for multydropdown
            projectId() {
                this.trackerData.projectId = this.trackUpdatRecord.PROJECT_ID ? this.store.getProjectsByUser.find((data) => data.projectId == this.trackUpdatRecord.PROJECT_ID) : null
            },
            //If task id get number from backend then set custom object for multydropdown
            taskId() {
                this.trackerData.taskId = this.trackUpdatRecord.TASK_ID ? this.store.getTasksFromProject.find((data) => data.value == this.trackUpdatRecord.TASK_ID) : null
            },
            validHours() {
                let status = false
                if (!this.startTime) {
                    this.status = false
                    this.store.alertBOxForMessage({
                        "type": 'warning',
                        "open": true,
                        "message": "Please Enter start Date"
                    })
                } else if (!this.endTime) {
                    this.status = false
                    this.store.alertBOxForMessage({
                        "type": 'warning',
                        "open": true,
                        "message": "Please Enter End Date"
                    })
                }
                //console.log("end",moment(moment(this.endTime.HH+':'+this.endTime.mm, 'hh:mm')))
                else if (this.startTime && this.endTime) {
    
                    let dateStart = moment(new Date(this.trackerData.DateSet), "YYYY-MM-DD").format("YYYY-MM-DD")
                    let startDateTime = moment(dateStart + ' ' + this.startTime, "YYYY-MM-DD HH:mm")
                    let endDateTime = moment(dateStart + ' ' + this.endTime, "YYYY-MM-DD HH:mm")
                    let today = moment(dateAndTimeZone(moment(), dateFormat))
                    if (startDateTime.valueOf() > endDateTime.valueOf() || endDateTime.valueOf() > today.valueOf()) {
                        this.store.alertBOxForMessage({
                            "type": 'warning',
                            "open": true,
                            "message": "You can not enter time for the future. Please update the time entered"
                        })
                    } else {
                        status = true
                        let sec = getSecondsFromDate({
                            startDate: moment(this.startTime, 'hh:mm'),
                            endDate: moment(this.endTime, 'hh:mm')
                        }, 'seconds')
    
                        this.trackerData.startDate = startDateTime.format("YYYY-MM-DD HH:mm:ss")
                        this.trackerData.DateSet = startDateTime.format("YYYY-MM-DD HH:mm:ss")
                        //this.manualData.SelectedDate = startDateTime.format("YYYY-MM-DD HH:mm:ss")
                        this.trackerData.startTime = startDateTime.format("YYYY-MM-DD HH:mm:ss")
                        this.trackerData.stopTime = endDateTime.format("YYYY-MM-DD HH:mm:ss")
                        // this.manualData.endDate = endDateTime.format("YYYY-MM-DD HH:mm:ss")
                        this.totalHours = formatter(sec)
                        this.trackerData.totalHours = sec
                    }
                }
                return status
            },
            //Get time time diffrece between start date and end date
            getTimeDiff() {
                if (this.startTime && this.endTime) {
                    let dateStart = moment(new Date(this.trackerData.DateSet), "YYYY-MM-DD").format("YYYY-MM-DD")
                    let startDateTime = moment(dateStart + ' ' + this.startTime, "YYYY-MM-DD HH:mm")
                    let endDateTime = moment(dateStart + ' ' + this.endTime, "YYYY-MM-DD HH:mm")
                    let today = moment(dateAndTimeZone(moment(), dateFormat))
                    if (startDateTime.valueOf() > endDateTime.valueOf() || endDateTime.valueOf() > today.valueOf()) {
                        this.totalHours = "00:00:00"
                    } else {
                        let sec = getSecondsFromDate({
                            startDate: moment(this.startTime, 'hh:mm'),
                            endDate: moment(this.endTime, 'hh:mm')
                        }, 'seconds')
                        this.totalHours = formatter(sec)
                    }
                }
            }
    
        },
        data() {
            return {
                dateMask: {
                    input: dateFormat,
                },
                tagSelect: [],
                formData: {},
                textCountertlength: 2000,
                startTime: '00:00',
                endTime: '00:00',
                totalHours: "00:00:00",
                trackerData: {
                    projectId: null,
                    trackDescription: "",
                    taskId: null,
                    isBillable: true,
                    format: false,
                    trackId: 0,
                    startTime: dateAndTimeZone(moment(), dateTimeFromat),
                    DateStart: dateAndTimeZone(moment(), dateTimeFromat),
                    DateSet: dateAndTimeZone(moment(), dateTimeFromat),
                    stopTime: dateAndTimeZone(moment(), dateTimeFromat),
                    currentDate: dateAndTimeZone(moment(), dateTimeFromat),
                    createdBy: this.store.getUserInformation.id,
                    totalHours: 0,
                    timeformat: "12",
                    TagIds: null,
                    type: "TimeTrack",
                    UserGuide: this.$t('User_Guide_UpdateTimeEntry')
    
                }
            }
        }
    })
    </script>
    